// Dokan Express AI Shopping Assistant — orchestrates Gemini + backend.
// Inputs (from webhook body): { message: string, userId?: string }
// Output: { reply: string, intent: string, products: object[], suggestions: string[] }

const body = $input.first().json.body || {};
const message = String(body.message || '').trim();

if (!message) {
  return [{ json: { reply: "What can I help you find?", intent: 'FAQ', products: [], suggestions: [] } }];
}

const geminiKey = process.env.GEMINI_API_KEY;
if (!geminiKey) {
  throw new Error('GEMINI_API_KEY is not set in the n8n environment');
}

const backendUrl = process.env.DOKANXPRESS_BACKEND_URL || 'http://host.docker.internal:5000';

const systemPrompt = `You are a helpful shopping assistant for Dokan Express, an online marketplace.
Classify the user's message and respond with STRICTLY VALID JSON in this shape:
{
  "intent": "SEARCH" | "RECOMMEND" | "ORDER_STATUS" | "FAQ",
  "query": "<extracted product search keywords if intent is SEARCH or RECOMMEND, else empty>",
  "reply": "<a friendly 1-2 sentence reply for the customer>",
  "suggestions": ["<2-3 short follow-up question suggestions>"]
}

Intent guide:
- SEARCH: user wants a specific kind of product ("wireless headphones under $100", "red running shoes")
- RECOMMEND: user wants suggestions ("what's good for a coffee lover?", "gift ideas for a 30 year old gamer")
- ORDER_STATUS: asking about an existing order
- FAQ: returns, shipping, payment methods, store policies, etc.

The reply must be conversational and concise. Do NOT list product names or prices in the reply — those will be attached as cards by the application. Output ONLY the JSON object, no markdown fences, no commentary.`;

const geminiUrl = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=' + encodeURIComponent(geminiKey);
const geminiPayload = {
  contents: [
    { role: 'user', parts: [{ text: systemPrompt + '\n\nUser message: ' + message }] }
  ],
  generationConfig: {
    temperature: 0.4,
    responseMimeType: 'application/json'
  }
};

const geminiRes = await fetch(geminiUrl, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(geminiPayload)
});

if (!geminiRes.ok) {
  const errText = await geminiRes.text();
  throw new Error('Gemini API error ' + geminiRes.status + ': ' + errText);
}

const geminiJson = await geminiRes.json();
const rawText = geminiJson?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (err) {
  parsed = { intent: 'FAQ', query: '', reply: rawText, suggestions: [] };
}

const intent = parsed.intent || 'FAQ';
const query = parsed.query || '';
const reply = parsed.reply || "Sorry, I didn't quite catch that.";
const suggestions = Array.isArray(parsed.suggestions) ? parsed.suggestions.slice(0, 3) : [];

let products = [];
if ((intent === 'SEARCH' || intent === 'RECOMMEND') && query) {
  const url = new URL(backendUrl + '/api/v1/products');
  url.searchParams.set('searchTerm', query);
  url.searchParams.set('limit', '5');
  url.searchParams.set('page', '1');

  try {
    const res = await fetch(url.toString());
    if (res.ok) {
      const json = await res.json();
      products = (json?.data || []).map((p) => ({
        id: p.id,
        name: p.name,
        price: p.price,
        image: Array.isArray(p.images) && p.images[0] ? p.images[0] : null,
        shop: p.shop?.shopName,
        category: p.category?.name,
        isFlashSale: !!p.isFlashSale,
        discount_percentage: p.discount_percentage || null
      }));
    }
  } catch (err) {
    // Backend unreachable — gracefully degrade with no products. The user-facing reply
    // from Gemini still goes through.
  }
}

return [{ json: { reply, intent, query, products, suggestions } }];
